-- Playbook metric catalog — the 1,000-metric Owner's Playbook as a living,
-- measurable target inside Truxon (not 1,000 hand-coded functions). Each metric
-- carries a status: live (computed today), needs_data (one instrumentation
-- away), external (needs a vendor feed — ELD/FMCSA/DAT/insurance), or
-- qualitative (board judgment, not a computed number). As we instrument a
-- source, its metrics flip needs_data → live and coverage rises. Trux reads
-- this to report progress and to answer "not captured yet — here's what we'd
-- need" honestly.

create table if not exists public.playbook_metrics (
  number int primary key,
  name text not null,
  definition text not null default '',
  owner_role text not null default '',
  category text not null default '',
  status text not null default 'needs_data' check (status in ('live','needs_data','external','qualitative')),
  source text not null default '',          -- where a live metric is computed
  target text not null default '',          -- the owner's target/threshold
  updated_at timestamptz not null default now()
);
create index if not exists playbook_metrics_status_idx on public.playbook_metrics (status);
create index if not exists playbook_metrics_cat_idx on public.playbook_metrics (category);

alter table public.playbook_metrics enable row level security;
drop policy if exists playbook_metrics_read on public.playbook_metrics;
create policy playbook_metrics_read on public.playbook_metrics for select to authenticated
  using (public.my_role() in ('admin','accountant','dispatcher'));
drop policy if exists playbook_metrics_write on public.playbook_metrics;
create policy playbook_metrics_write on public.playbook_metrics for all to authenticated
  using (public.my_role() = 'admin') with check (public.my_role() = 'admin');


-- Coverage: how far along we are toward the 1,000, by status and category.
create or replace function public.playbook_coverage()
returns jsonb language sql stable security definer set search_path = public as $$
  select case when public.my_role() not in ('admin','accountant','dispatcher') then null else
    jsonb_build_object(
      'total', (select count(*) from public.playbook_metrics),
      'by_status', (select jsonb_object_agg(status, n) from (select status, count(*) n from public.playbook_metrics group by status) s),
      'by_category', (select jsonb_agg(jsonb_build_object('category', category, 'live', live, 'total', total) order by category)
                        from (select category, count(*) filter (where status='live') live, count(*) total
                                from public.playbook_metrics group by category) c)
    ) end;
$$;

create or replace function public.playbook_metrics_list(p_status text default null, p_owner text default null, p_search text default null)
returns setof public.playbook_metrics language sql stable security definer set search_path = public as $$
  select * from public.playbook_metrics
   where public.my_role() in ('admin','accountant','dispatcher')
     and (p_status is null or status = p_status)
     and (p_owner is null or owner_role = p_owner)
     and (p_search is null or name ilike '%'||p_search||'%')
   order by number limit 300;
$$;

revoke execute on function public.playbook_coverage() from public, anon;
revoke execute on function public.playbook_metrics_list(text, text, text) from public, anon;
grant execute on function public.playbook_coverage() to authenticated;
grant execute on function public.playbook_metrics_list(text, text, text) to authenticated;
